mapper.select:
SELECT id, part_code, part_name, standard_code, standard_name, method, profession, oil_feed_type, feed_point, oil_models, oil_volume, next_check_time, creator_id, created_at, updated_at FROM lubrication_standard
AND creator_id = #{creatorId} AND standard_code LIKE CONCAT('%', #{standardCode}, '%') AND part_code LIKE CONCAT('%', #{partCode}, '%') AND part_name LIKE CONCAT('%', #{partName}, '%') AND feed_point LIKE CONCAT('%', #{feedPoint}, '%') AND oil_models LIKE CONCAT('%', #{oilModels}, '%') AND profession = #{profession} AND oil_feed_type = #{oilFeedType}
ORDER BY id DESC

SELECT id, part_code, part_name, standard_code, standard_name, method, profession, oil_feed_type,
       feed_point, oil_models, oil_volume, next_check_time, creator_id, created_at, updated_at
FROM lubrication_standard

    AND part_code = #{partCode}
    AND standard_code = #{standardCode}

SELECT id, part_code, part_name, standard_code, standard_name, method, profession, oil_feed_type,
       feed_point, oil_models, oil_volume, next_check_time, creator_id, created_at, updated_at
FROM lubrication_standard
WHERE id = #{id}

    AND creator_id = #{creatorId}

mapper.update:
UPDATE lubrication_standard
part_code = #{partCode}, part_name = #{partName}, standard_code = #{standardCode}, standard_name = #{standardName}, method = #{method}, profession = #{profession}, oil_feed_type = #{oilFeedType}, feed_point = #{feedPoint}, oil_models = #{oilModels}, oil_volume = #{oilVolume}, next_check_time = #{nextCheckTime}, updated_at = #{updatedAt},
WHERE id = #{id}
